import { Injectable } from '@nestjs/common';
import { PassportStrategy } from '@nestjs/passport';
import { Strategy, Profile } from 'passport-discord';
import { DatabaseService } from '../../database/database.service';

/**
 * Discord OAuth Strategy
 *
 * Handles Discord OAuth authentication flow.
 * Creates or updates user account based on Discord profile.
 *
 * Requirements: 9.2
 */
@Injectable()
export class DiscordStrategy extends PassportStrategy(Strategy, 'discord') {
  constructor(private readonly db: DatabaseService) {
    super({
      clientID: process.env.DISCORD_CLIENT_ID || '',
      clientSecret: process.env.DISCORD_CLIENT_SECRET || '',
      callbackURL: process.env.DISCORD_CALLBACK_URL || 'http://localhost:3000/api/auth/oauth/discord/callback',
      scope: ['identify', 'email'],
    });
  }

  async validate(
    accessToken: string,
    refreshToken: string,
    profile: Profile,
  ): Promise<any> {
    const { id, username, email } = profile;

    if (!email) {
      throw new Error('Email not provided by Discord');
    }

    // Check if user exists with this Discord ID
    let user = await this.db.user.findFirst({
      where: {
        oauthProvider: 'discord',
        oauthId: id,
      },
    });

    if (user) {
      // Update existing user
      user = await this.db.user.update({
        where: { id: user.id },
        data: {
          username: username || user.username,
          email: email || user.email,
        },
      });
    } else {
      // Check if email already exists
      const existingUser = await this.db.user.findUnique({
        where: { email },
      });

      if (existingUser) {
        // Link Discord to existing account
        user = await this.db.user.update({
          where: { id: existingUser.id },
          data: {
            oauthProvider: 'discord',
            oauthId: id,
          },
        });
      } else {
        // Create new user
        user = await this.db.user.create({
          data: {
            email,
            username: username || `discord_${id}`,
            oauthProvider: 'discord',
            oauthId: id,
            emailVerified: true, // OAuth emails are pre-verified
            passwordHash: '', // No password for OAuth users
          },
        });
      }
    }

    return {
      id: user.id,
      email: user.email,
      username: user.username,
      role: user.role,
    };
  }
}

import { Injectable } from '@nestjs/common';
import { PassportStrategy } from '@nestjs/passport';
import { Strategy, VerifyCallback, Profile } from 'passport-google-oauth20';
import { DatabaseService } from '../../database/database.service';

/**
 * Google OAuth Strategy
 *
 * Handles Google OAuth authentication flow.
 * Creates or updates user account based on Google profile.
 *
 * Requirements: 9.2
 */
@Injectable()
export class GoogleStrategy extends PassportStrategy(Strategy, 'google') {
  constructor(private readonly db: DatabaseService) {
    super({
      clientID: process.env.GOOGLE_CLIENT_ID || '',
      clientSecret: process.env.GOOGLE_CLIENT_SECRET || '',
      callbackURL: process.env.GOOGLE_CALLBACK_URL || 'http://localhost:3000/api/auth/oauth/google/callback',
      scope: ['email', 'profile'],
    });
  }

  async validate(
    accessToken: string,
    refreshToken: string,
    profile: Profile,
    done: VerifyCallback,
  ): Promise<any> {
    const { id, displayName, emails } = profile;

    if (!emails || emails.length === 0) {
      return done(new Error('Email not provided by Google'), undefined);
    }

    const email = emails[0].value;

    try {
      // Check if user exists with this Google ID
      let user = await this.db.user.findFirst({
        where: {
          oauthProvider: 'google',
          oauthId: id,
        },
      });

      if (user) {
        // Update existing user
        user = await this.db.user.update({
          where: { id: user.id },
          data: {
            username: displayName || user.username,
            email: email || user.email,
          },
        });
      } else {
        // Check if email already exists
        const existingUser = await this.db.user.findUnique({
          where: { email },
        });

        if (existingUser) {
          // Link Google to existing account
          user = await this.db.user.update({
            where: { id: existingUser.id },
            data: {
              oauthProvider: 'google',
              oauthId: id,
            },
          });
        } else {
          // Create new user
          user = await this.db.user.create({
            data: {
              email,
              username: displayName || `google_${id}`,
              oauthProvider: 'google',
              oauthId: id,
              emailVerified: true, // OAuth emails are pre-verified
              passwordHash: '', // No password for OAuth users
            },
          });
        }
      }

      const userPayload = {
        id: user.id,
        email: user.email,
        username: user.username,
        role: user.role,
      };

      done(null, userPayload);
    } catch (error) {
      done(error as Error, undefined);
    }
  }
}

