/**
 * OAuth callback handler
 *
 * Called after successful OAuth authentication.
 * User is already created/updated by the OAuth strategy.
 * Generates JWT token pair for the authenticated user.
 *
 * Requirements: 9.2
 */
async oauthCallback(user: any): Promise<{
  accessToken: string;
  refreshToken: string;
  expiresIn: number;
}> {
  if (!user || !user.id) {
    throw new UnauthorizedException('OAuth authentication failed');
  }

  // Generate token pair for OAuth user
  return this.generateTokenPair(user.id);
}
